import{_ as e,c as t,o as a,b as n}from"./app.cec98555.js";const _='{"title":"Universal color music notation for visualization and communication","description":"","frontmatter":{"template":"home","title":"Universal color music notation for visualization and communication","actionLink":"/enter.html","actionText":"Enter","altActionLink":"/ru.html","altActionText":"\u0412\u043E\u0439\u0442\u0438","icon":"/media/logo/logo.svg"},"headers":[],"relativePath":"index.md"}',o={},i=n('<h1 id="the-international-visual-music-language-to-learn-and-to-experiment-with" tabindex="-1">The international visual music language to learn and to experiment with <a class="header-anchor" href="#the-international-visual-music-language-to-learn-and-to-experiment-with" aria-hidden="true">#</a></h1><p>Chromatone is an ongoing research and experiment to induce a synchronised artificial synesthesia for personal music learning and exploration along with collective practice and performance. Imagine if once we agree on a certain way to connect notes and colors? It can empower our music perception with vision, the main modality for most of humans. Let&#39;s try to do it now!</p><p>We&#39;re building a visual <a href="./theory/">music theory study</a>, that may help beginners learn complex music concepts in color. <a href="./apps/">Interactive web-apps</a> expand the knowledge and grow deeper music awareness.</p><p>For those, who want to touch and feel the colorful notes we have a <a href="./shop/">Sticker shop</a>. While those who are interested in further project development may consider <a href="./support/">supporting</a> <a href="./contact/author/">us</a> today.</p>',4),r=[i];function s(c,l,h,p,d,m){return a(),t("div",null,r)}var f=e(o,[["render",s]]);export{_ as __pageData,f as default};
